// --- CRC32 ---
const makeCRCTable = () => {
  let c;
  const crcTable = [];
  for (let n = 0; n < 256; n++) {
    c = n;
    for (let k = 0; k < 8; k++) {
      c = ((c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1));
    }
    crcTable[n] = c;
  }
  return crcTable;
};

const crc32 = (str) => {
  const crcTable = makeCRCTable();
  let crc = 0 ^ (-1);
  for (let i = 0; i < str.length; i++) {
    crc = (crc >>> 8) ^ crcTable[(crc ^ str.charCodeAt(i)) & 0xFF];
  }
  return (crc ^ (-1)) >>> 0;
};

const cleanField = (value) => {
  if (!value) return value;
  return value
    .split('\n')
    .map(x => x.trim())
    .filter((v, i, a) => a && a.indexOf(v) === i)
    .join(' ');
};

